func solve(words: Array<String>): Array<Int64> {
    let n = words.count
    if n == 0 {
        return Array<Int64>()
    }
    if n == 1 {
        return [0]
    }

    // Compute the prefixes array
    var prefixes = [Int64]()
    for i in 0..<n-1 {
        let a = words[i]
        let b = words[i+1]
        var len = 0
        while len < min(a.count, b.count) && a[len] == b[len] {
            len += 1
        }
        prefixes.append(Int64(len))
    }

    // Compute left_max and right_max arrays
    var left_max = [Int64](repeating: 0, count: prefixes.count)
    left_max[0] = prefixes[0]
    for i in 1..<prefixes.count {
        left_max[i] = max(left_max[i-1], prefixes[i])
    }

    var right_max = [Int64](repeating: 0, count: prefixes.count)
    right_max[prefixes.count-1] = prefixes[prefixes.count-1]
    for i in (prefixes.count-2)...0 {
        right_max[i] = max(prefixes[i], right_max[i+1])
    }

    var answer = [Int64](repeating: 0, count: n)
    for i in 0..<n {
        if n == 1 {
            answer[i] = 0
            continue
        }

        let modifiedLength = n - 1
        if modifiedLength < 2 {
            answer[i] = 0
            continue
        }

        var maxOriginal = 0
        if i == 0 {
            if prefixes.count >= 1 {
                if prefixes.count >= 2 {
                    maxOriginal = right_max[1]
                } else {
                    maxOriginal = 0
                }
            }
        } else if i == n-1 {
            if prefixes.count > 0 {
                if n-3 >= 0 {
                    maxOriginal = left_max[n-3]
                } else {
                    maxOriginal = 0
                }
            }
        } else {
            let leftPart = i-2 >= 0 ? left_max[i-2] : 0
            let rightPart = i+1 <= prefixes.count-1 ? right_max[i+1] : 0
            maxOriginal = max(leftPart, rightPart)
        }

        if i != 0 && i != n-1 {
            let a = words[i-1]
            let b = words[i+1]
            var len = 0
            while len < min(a.count, b.count) && a[len] == b[len] {
                len += 1
            }
            let newPair = Int64(len)
            answer[i] = max(maxOriginal, newPair)
        } else {
            answer[i] = maxOriginal
        }
    }

    return answer
