from typing import List

def solve(words: List[str]) -> List[int]:
    n = len(words)
    if n < 2:
        return [0] * n

    m = n - 1
    def lcp_length(a: str, b: str) -> int:
        min_len = min(len(a), len(b))
        for i in range(min_len):
            if a[i] != b[i]:
                return i
        return min_len

    lcp = [0] * m
    for j in range(m):
        lcp[j] = lcp_length(words[j], words[j+1])

    prefix_max = [0] * m
    prefix_max[0] = lcp[0]
    for i in range(1, m):
        prefix_max[i] = max(prefix_max[i-1], lcp[i])

    suffix_max = [0] * m
    suffix_max[-1] = lcp[-1]
    for i in range(m-2, -1, -1):
        suffix_max[i] = max(suffix_max[i+1], lcp[i])

    answer = [0] * n
    for i in range(n):
        if n == 2:
            answer[i] = 0
            continue

        if i == 0:
            original_max = suffix_max[1] if m >= 2 else 0
        elif i == n-1:
            original_max = prefix_max[m-2] if m >= 2 else 0
        else:
            left = prefix_max[i-2] if (i-2) >= 0 else 0
            right = suffix_max[i+1] if (i+1) < m else 0
            original_max = max(left, right)

        new_pair_lcp = 0
        if i != 0 and i != n-1:
            new_pair_lcp = lcp_length(words[i-1], words[i+1])

        answer[i] = max(original_max, new_pair_lcp)

    return answer
